import React, { useState, useCallback, useRef } from 'react';
import {
  FlatList,
  View,
  Text,
  ActivityIndicator,
  StyleSheet,
  Dimensions,
} from 'react-native';

const PAGE_SIZE = 20;
const TOTAL_ITEMS = 100; // For demo purposes

interface Item {
  id: number;
  title: string;
  description: string;
}

export default function InfiniteScrollList() {
  const [items, setItems] = useState<Item[]>([]);
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const flatListRef = useRef<FlatList>(null);

  const fetchItems = useCallback(async (pageNum: number) => {
    setLoading(true);

    // Simulate API call delay
    await new Promise(resolve => setTimeout(resolve, 1000));

    const start = (pageNum - 1) * PAGE_SIZE;
    const end = Math.min(start + PAGE_SIZE, TOTAL_ITEMS);
    const pageItems: Item[] = [];

    for (let i = start; i < end; i++) {
      pageItems.push({
        id: i + 1,
        title: `Item ${i + 1}`,
        description: `This is a description for item ${i + 1}.`,
      });
    }

    setItems(prev => [...prev, ...pageItems]);
    setPage(prev => prev + 1);
    setLoading(false);

    // Stop loading when we've fetched all items
    if (end >= TOTAL_ITEMS) {
      setHasMore(false);
    }
  }, []);

  const onEndReached = useCallback(() => {
    if (!loading && hasMore) {
      fetchItems(page + 1);
    }
  }, [loading, hasMore, page, fetchItems]);

  const renderItem = useCallback(({ item }: { item: Item }) => (
    <View style={styles.card}>
      <Text style={styles.title}>{item.title}</Text>
      <Text style={styles.description} numberOfLines={2}>
        {item.description}
      </Text>
    </View>
  ), []);

  const renderFooter = useCallback(() => (
    loading ? (
      <View style={styles.footer}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading more...</Text>
      </View>
    ) : null
  ), [loading]);

  const renderHeader = useCallback(() => (
    <View style={styles.header}>
      <Text style={styles.headerTitle}>Infinite Scroll Demo</Text>
      <Text style={styles.headerSubtitle}>
        Page {page} | Items: {items.length} / {TOTAL_ITEMS}
      </Text>
    </View>
  ), [page, items.length]);

  return (
    <View style={styles.container}>
      <FlatList
        ref={flatListRef}
        data={items}
        renderItem={renderItem}
        keyExtractor={(item) => item.id.toString()}
        onEndReached={onEndReached}
        onEndReachedThreshold={0.5}
        contentContainerStyle={styles.listContent}
        showsVerticalScrollIndicator={true}
        initialNumToRender={10}
        maxToRenderPerBatch={10}
        windowSize={2}
      />
      {renderFooter()}
    </View>
  );
}

