import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  Dimensions,
  Platform,
} from 'react-native';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

export default function ResponsiveLayout() {
  const [isTablet, setIsTablet] = useState(false);

  useEffect(() => {
    const handleDimensionsChange = () => {
      setIsTablet(SCREEN_WIDTH >= 768);
    };

    handleDimensionsChange();

    // Note: In React Native, window dimensions don't change dynamically
    // but we can use a threshold for initial render
    return () => {};
  }, []);

  const Card = ({ title, description }: { title: string; description: string }) => (
    <View style={styles.card}>
      <Text style={styles.cardTitle}>{title}</Text>
      <Text style={styles.cardDescription}>{description}</Text>
    </View>
  );

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>Responsive Layout</Text>
        <Text style={styles.subtitle}>
          {isTablet ? 'Tablet View (2 columns)' : 'Phone View (1 column)'}
        </Text>
      </View>

      <View style={[styles.content, isTablet && styles.twoColumns]}>
        <Card title="Item 1" description="First responsive item content here" />
        <Card title="Item 2" description="Second responsive item content here" />
        <Card title="Item 3" description="Third responsive item content here" />
        <Card title="Item 4" description="Fourth responsive item content here" />
      </View>

      <View style={styles.footer}>
        <Text style={styles.footerText}>
          Screen Width: {SCREEN_WIDTH}px
        </Text>
      </View>
    </ScrollView>
  );
}

