import React, { useState, useCallback, useEffect } from 'react';
import {
  View,
  Text,
  ActivityIndicator,
  StyleSheet,
  TouchableOpacity,
  Alert,
} from 'react-native';

interface User {
  id: number;
  name: string;
  email: string;
}

interface ApiResponse<T> {
  data: T | null;
  error: string | null;
}

const API_BASE_URL = 'https://jsonplaceholder.typicode.com/users';

export const DataFetcher: React.FC<{ onRefresh?: () => void }> = ({ onRefresh }) => {
  const [data, setData] = useState<User[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async (): Promise<ApiResponse<User[]>> => {
    try {
      const response = await fetch(`${API_BASE_URL}?_limit=5&_skip=0`);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const jsonData = await response.json();
      return { data: jsonData, error: null };
    } catch (err) {
      console.error('Fetch error:', err);
      return { data: null, error: err instanceof Error ? err.message : 'Unknown error' };
    }
  }, []);

  useEffect(() => {
    let abortController = new AbortController();
    const signal = abortController.signal;

    const loadData = async () => {
      try {
        const result = await fetchData();

        if (!signal.aborted) {
          setData(result.data || []);
          setError(result.error || null);
        }
      } catch (err) {
        if (!signal.aborted) {
          setError(err instanceof Error ? err.message : 'Failed to load data');
        }
      } finally {
        setLoading(false);
      }
    };

    loadData();

    return () => {
      abortController.abort();
    };
  }, [fetchData]);

  const handleRefresh = useCallback(() => {
    if (onRefresh) {
      onRefresh();
    }
  }, [onRefresh]);

  const handleRetry = async () => {
    setLoading(true);
    setError(null);

    try {
      const result = await fetchData();

      if (!result.error && result.data) {
        setData(result.data);
      } else {
        setError(result.error || 'Failed to refresh data');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Refresh failed');
    } finally {
      setLoading(false);
    }
  };

  const handleRetryPress = () => {
    if (loading) return;

    Alert.alert(
      'Retry',
      'Do you want to retry fetching the data?',
      [
        { text: 'Cancel', style: 'cancel' },
        { 
          text: 'Retry', 
          onPress: handleRetry,
          style: 'default'
        }
      ]
    );
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading data...</Text>
      </View>
    );
  }

  if (error) {
    return (
      <View style={styles.container}>
        <Text style={styles.errorTitle}>Error</Text>
        <Text style={styles.errorText}>{error}</Text>
        <TouchableOpacity 
          style={styles.retryButton}
          onPress={handleRetryPress}
          disabled={loading}
        >
          <Text style={styles.retryButtonText}>Retry</Text>
        </TouchableOpacity>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>Users List</Text>
        {onRefresh && (
          <TouchableOpacity 
            style={styles.refreshButton}
            onPress={handleRefresh}
            disabled={loading}
          >
            <Text style={styles.refreshButtonText}>↻ Refresh</Text>
          </TouchableOpacity>
        )}
      </View>

      {data.length === 0 ? (
        <View style={styles.emptyContainer}>
          <Text style={styles.emptyText}>No data available</Text>
        </View>
      ) : (
        <View style={styles.listContainer}>
          {data.map((user) => (
            <View key={user.id} style={styles.card}>
              <Text style={styles.name}>{user.name}</Text>
              <Text style={styles.email}>{user.email}</Text>
              <Text style={styles.id}>ID: {user.id}</Text>
            </View>
          ))}
        </View>
      )}
    </View>
  );
};

