import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, ActivityIndicator, PermissionsAndroid, Platform } from 'react-native';
import * as Location from 'expo-location';

export default function App() {
  const [location, setLocation] = useState<Location.LocationObject | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    (async () => {
      try {
        // Request location permission
        let status: Location.LocationStatus;

        if (Platform.OS === 'android') {
          // Android requires explicit permission request
          const granted = await PermissionsAndroid.request(
            PermissionsAndroid.PERMISSIONS.ACCESS_FINE_LOCATION,
            {
              title: 'Location Permission',
              message: 'This app needs access to your location to show GPS coordinates.',
              buttonNegative: 'Cancel',
              buttonPositive: 'OK',
            }
          );

          if (granted === PermissionsAndroid.RESULTS.GRANTED) {
            status = await Location.requestForegroundPermissionsAsync();
          } else {
            throw new Error('Permission denied');
          }
        } else {
          // iOS handles permissions differently
          const result = await Location.requestForegroundPermissionsAsync();
          status = result;
        }

        if (status.granted) {
          const currentLocation = await Location.getCurrentPositionAsync({
            accuracy: Location.Accuracy.Balanced,
            timeInterval: 5000,
            distanceInterval: 10,
          });

          setLocation(currentLocation.coords);
        } else {
          throw new Error('Permission denied');
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Unknown error occurred');
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Getting your location...</Text>
      </View>
    );
  }

  if (error) {
    return (
      <View style={styles.container}>
        <Text style={styles.errorTitle}>Error</Text>
        <Text style={styles.errorText}>{error}</Text>
        <Text style={styles.hintText}>Please enable location permissions in app settings.</Text>
      </View>
    );
  }

  if (!location) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading location...</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Your GPS Coordinates</Text>

      <View style={styles.card}>
        <Text style={styles.label}>Latitude:</Text>
        <Text style={styles.value}>{location.latitude.toFixed(6)}</Text>

        <Text style={styles.label}>Longitude:</Text>
        <Text style={styles.value}>{location.longitude.toFixed(6)}</Text>

        <Text style={styles.label}>Altitude:</Text>
        <Text style={styles.value}>{location.altitude?.toFixed(2) || 'N/A'} m</Text>

        <Text style={styles.label}>Accuracy:</Text>
        <Text style={styles.value}>{location.accuracy.toFixed(1)} m</Text>

        <Text style={styles.label}>Heading:</Text>
        <Text style={styles.value}>{location.heading?.toFixed(0) || 'N/A'}°</Text>

        <Text style={styles.label}>Speed:</Text>
        <Text style={styles.value}>{location.speed?.toFixed(1) || 0} m/s</Text>
      </View>

      <View style={styles.timestampContainer}>
        <Text style={styles.timestampLabel}>Updated:</Text>
        <Text style={styles.timestampValue}>
          {new Date(location.timestamp).toLocaleTimeString()}
        </Text>
      </View>
    </View>
  );
}

