import React, { useState, useEffect } from 'react';
import { View, Text, TextInput, Button, FlatList, StyleSheet, Alert, Platform } from 'react-native';
import * as SQLite from 'expo-sqlite';

const DB_NAME = 'todos.db';
const TABLE_NAME = 'todos';

export default function App() {
  const [todos, setTodos] = useState<any[]>([]);
  const [newTodo, setNewTodo] = useState('');

  useEffect(() => {
    initDatabase();
  }, []);

  async function initDatabase() {
    try {
      await SQLite.openDatabaseAsync(DB_NAME);

      // Create table if it doesn't exist
      await SQLite.executeSqlAsync(
        `CREATE TABLE IF NOT EXISTS ${TABLE_NAME} (
          id INTEGER PRIMARY KEY AUTOINCREMENT,
          title TEXT NOT NULL,
          completed INTEGER DEFAULT 0,
          created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        )`
      );

      // Fetch all todos
      const result = await SQLite.executeSqlAsync(
        `SELECT * FROM ${TABLE_NAME} ORDER BY created_at DESC`
      );

      setTodos(result.rows.map((row: any) => ({
        id: row.id,
        title: row.title,
        completed: row.completed,
        created_at: row.created_at
      })));

    } catch (error) {
      console.error('Database initialization error:', error);
      Alert.alert('Error', 'Failed to initialize database');
    }
  }

  async function addTodo(title: string) {
    if (!title.trim()) {
      Alert.alert('Error', 'Please enter a todo title');
      return;
    }

    try {
      await SQLite.openDatabaseAsync(DB_NAME);

      const result = await SQLite.executeSqlAsync(
        `INSERT INTO ${TABLE_NAME} (title) VALUES (?)`,
        [title.trim()]
      );

      // Fetch updated list
      const rows = await SQLite.executeSqlAsync(
        `SELECT * FROM ${TABLE_NAME} ORDER BY created_at DESC`
      );

      setTodos(rows.rows.map((row: any) => ({
        id: row.id,
        title: row.title,
        completed: row.completed,
        created_at: row.created_at
      })));

      setNewTodo('');
    } catch (error) {
      console.error('Add todo error:', error);
      Alert.alert('Error', 'Failed to add todo');
    }
  }

  async function toggleTodo(id: number) {
    try {
      await SQLite.openDatabaseAsync(DB_NAME);

      const result = await SQLite.executeSqlAsync(
        `UPDATE ${TABLE_NAME} SET completed = NOT completed WHERE id = ?`,
        [id]
      );

      // Fetch updated list
      const rows = await SQLite.executeSqlAsync(
        `SELECT * FROM ${TABLE_NAME} ORDER BY created_at DESC`
      );

      setTodos(rows.rows.map((row: any) => ({
        id: row.id,
        title: row.title,
        completed: row.completed,
        created_at: row.created_at
      })));

    } catch (error) {
      console.error('Toggle todo error:', error);
      Alert.alert('Error', 'Failed to toggle todo');
    }
  }

  async function deleteTodo(id: number) {
    try {
      await SQLite.openDatabaseAsync(DB_NAME);

      const result = await SQLite.executeSqlAsync(
        `DELETE FROM ${TABLE_NAME} WHERE id = ?`,
        [id]
      );

      // Fetch updated list
      const rows = await SQLite.executeSqlAsync(
        `SELECT * FROM ${TABLE_NAME} ORDER BY created_at DESC`
      );

      setTodos(rows.rows.map((row: any) => ({
        id: row.id,
        title: row.title,
        completed: row.completed,
        created_at: row.created_at
      })));

    } catch (error) {
      console.error('Delete todo error:', error);
      Alert.alert('Error', 'Failed to delete todo');
    }
  }

  async function clearAllTodos() {
    try {
      await SQLite.openDatabaseAsync(DB_NAME);

      const result = await SQLite.executeSqlAsync(
        `DELETE FROM ${TABLE_NAME}`
      );

      // Fetch updated list
      const rows = await SQLite.executeSqlAsync(
        `SELECT * FROM ${TABLE_NAME} ORDER BY created_at DESC`
      );

      setTodos(rows.rows.map((row: any) => ({
        id: row.id,
        title: row.title,
        completed: row.completed,
        created_at: row.created_at
      })));

    } catch (error) {
      console.error('Clear todos error:', error);
      Alert.alert('Error', 'Failed to clear todos');
    }
  }

  const renderTodo = ({ item }: { item: any }) => (
    <View style={styles.todoItem}>
      <Text 
        style={[
          styles.todoText, 
          item.completed && styles.todoCompleted
        ]}
        onPress={() => toggleTodo(item.id)}
      >
        {item.title}
      </Text>
      <View style={styles.buttonContainer}>
        <Button 
          title="Delete" 
          color="#ff4444"
          onPress={() => deleteTodo(item.id)}
        />
      </View>
    </View>
  );

  return (
    <View style={styles.container}>
      <Text style={styles.title}>SQLite Todos</Text>

      <TextInput
        style={styles.input}
        placeholder="Enter new todo..."
        value={newTodo}
        onChangeText={setNewTodo}
        onSubmitEditing={(e) => {
          addTodo(e.nativeEvent.text);
        }}
      />

      <Button 
        title="Add Todo" 
        onPress={() => addTodo(newTodo)}
        style={styles.addButton}
      />

      <FlatList
        data={todos}
        renderItem={renderTodo}
        keyExtractor={(item) => item.id.toString()}
        contentContainerStyle={styles.list}
      />

      <Button 
        title="Clear All Todos" 
        onPress={clearAllTodos}
        color="#ff4444"
      />
    </View>
  );
}

