import React, { useState } from 'react';
import { View, Text, TextInput, Button, StyleSheet, Alert } from 'react-native';
import * as SecureStore from 'expo-secure-store';

// Type definitions
interface AuthToken {
  token: string;
  expiresAt?: number;
}

const App = () => {
  const [token, setToken] = useState<string>('');
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [isLoading, setIsLoading] = useState<boolean>(false);

  // Save authentication token to secure storage
  const saveToken = async (newToken: string) => {
    try {
      await SecureStore.setItemAsync('auth_token', newToken);
      setToken(newToken);
      setIsAuthenticated(true);
      Alert.alert('Success', 'Token saved securely!');
    } catch (error) {
      console.error('Error saving token:', error);
      Alert.alert('Error', 'Failed to save token');
    }
  };

  // Retrieve authentication token from secure storage
  const getToken = async (): Promise<string | null> => {
    try {
      const savedToken = await SecureStore.getItemAsync('auth_token');
      return savedToken || null;
    } catch (error) {
      console.error('Error retrieving token:', error);
      return null;
    }
  };

  // Clear the stored token
  const clearToken = async () => {
    try {
      await SecureStore.deleteItemAsync('auth_token');
      setToken('');
      setIsAuthenticated(false);
      Alert.alert('Success', 'Token cleared!');
    } catch (error) {
      console.error('Error clearing token:', error);
      Alert.alert('Error', 'Failed to clear token');
    }
  };

  // Simulate login - save a sample token
  const handleLogin = () => {
    setIsLoading(true);
    setTimeout(() => {
      const mockToken = `mock_jwt_token_${Date.now()}`;
      saveToken(mockToken);
      setIsLoading(false);
    }, 1000);
  };

  // Simulate logout - clear the token
  const handleLogout = () => {
    clearToken();
  };

  // Check if we have a stored token on mount
  React.useEffect(() => {
    const checkStoredToken = async () => {
      const savedToken = await getToken();
      if (savedToken) {
        setToken(savedToken);
        setIsAuthenticated(true);
      }
    };
    checkStoredToken();
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Secure Token Storage</Text>

      <View style={styles.statusContainer}>
        <Text style={styles.statusText}>
          {isAuthenticated ? '✓ Authenticated' : '✗ Not authenticated'}
        </Text>
      </View>

      {token && (
        <View style={styles.tokenContainer}>
          <Text style={styles.label}>Stored Token:</Text>
          <Text style={styles.tokenValue} numberOfLines={3}>
            {token.substring(0, 20)}...{token.substring(token.length - 10)}
          </Text>
        </View>
      )}

      <View style={styles.buttonContainer}>
        {!isAuthenticated ? (
          <Button
            title="Login (Save Token)"
            onPress={handleLogin}
            disabled={isLoading}
          />
        ) : (
          <Button
            title="Logout (Clear Token)"
            onPress={handleLogout}
          />
        )}
      </View>

      <View style={styles.infoContainer}>
        <Text style={styles.infoText}>
          This app uses expo-secure-store to securely save and retrieve authentication tokens.
        </Text>
        <Text style={styles.infoText}>
          Tokens are encrypted and stored on the device's secure storage.
        </Text>
      </View>
    </View>
  );
};

