import React, { useRef, useState } from 'react';
import { View, StyleSheet, Dimensions, Animated, Text } from 'react-native';
import { GestureHandlerRootView, PanGestureHandler, State } from 'react-native-gesture-handler';
import Reanimated, { useAnimatedStyle, useSharedValue, withSpring, withTiming } from 'react-native-reanimated';

const SNAP_DURATION = 300;
const SNAP_TENSION = 15;
const SNAP_STIFFNESS = 200;

export default function DraggableBox() {
  const panX = useRef(new Animated.Value(0)).current;
  const panY = useRef(new Animated.Value(0)).current;

  const [isDragging, setIsDragging] = useState(false);
  const [originalPosition, setOriginalPosition] = useState({ x: 0, y: 0 });

  const handleGestureEvent = (event: any) => {
    if (event.state === State.ACTIVE) {
      setIsDragging(true);
      Animated.parallel([
        Animated.timing(panX, {
          toValue: event.translationX,
          duration: 16,
          useNativeDriver: false,
        }),
        Animated.timing(panY, {
          toValue: event.translationY,
          duration: 16,
          useNativeDriver: false,
        }),
      ]).start();
    } else if (event.state === State.END) {
      setIsDragging(false);

      const velocityX = event.velocityX;
      const velocityY = event.velocityY;
      const threshold = 50;

      Animated.parallel([
        Animated.spring(panX, {
          toValue: Math.abs(velocityX) > threshold ? 0 : originalPosition.x,
          tension: SNAP_TENSION,
          friction: SNAP_STIFFNESS,
          useNativeDriver: false,
        }),
        Animated.spring(panY, {
          toValue: Math.abs(velocityY) > threshold ? 0 : originalPosition.y,
          tension: SNAP_TENSION,
          friction: SNAP_STIFFNESS,
          useNativeDriver: false,
        }),
      ]).start();
    }
  };

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [
        { translateX: panX.value },
        { translateY: panY.value },
      ],
    };
  });

  const boxWidth = Dimensions.get('window').width * 0.8;
  const boxHeight = 150;
  const boxStyle = {
    width: boxWidth,
    height: boxHeight,
    backgroundColor: isDragging ? '#4A90E2' : '#34C759',
    borderRadius: 16,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.1,
    shadowRadius: 8,
    elevation: 5,
  };

  return (
    <GestureHandlerRootView style={{ flex: 1 }}>
      <View style={styles.container}>
        <Text style={styles.title}>Draggable Box</Text>
        <Text style={styles.subtitle}>Drag and release to snap back</Text>

        <PanGestureHandler onGestureEvent={handleGestureEvent} hitSlop={{ top: 50, bottom: 50, left: 50, right: 50 }}>
          <Animated.View style={[styles.boxContainer, animatedStyle]}>
            <View style={[boxStyle, { backgroundColor: isDragging ? '#4A90E2' : '#34C759' }]}>
              <Text style={styles.boxText}>Drag Me!</Text>
            </View>
          </Animated.View>
        </PanGestureHandler>

        <View style={styles.infoContainer}>
          <Text style={styles.infoText}>Current Position:</Text>
          <Text style={styles.infoValue}>X: {panX.value.toFixed(1)} | Y: {panY.value.toFixed(1)}</Text>
        </View>
      </View>
    </GestureHandlerRootView>
  );
}

