const SwipeCardStack: React.FC = () => {
  const [cards, setCards] = useState<CardData[]>(initialCards);
  const [currentIndex, setCurrentIndex] = useState(0);

  const translateX = useSharedValue(0);
  const rotate = useSharedValue(0);
  const scale = useSharedValue(1);
  const opacity = useSharedValue(1);

  const handleSwipe = (direction: 'left' | 'right') => {
    if (currentIndex >= cards.length) return;

    const targetTranslateX = direction === 'left' ? -CARD_WIDTH : CARD_WIDTH;
    const targetRotate = direction === 'left' ? -30 : 30;
    const targetScale = direction === 'left' ? 0.8 : 1.2;
    const targetOpacity = 0;

    translateX.value = withSpring(targetTranslateX, {
      damping: 15,
      stiffness: 40,
      overshootClamping: false,
    });

    rotate.value = withSpring(targetRotate, {
      damping: 12,
      stiffness: 300,
      overshootClamping: true,
    });

    scale.value = withSpring(targetScale, {
      damping: 15,
      stiffness: 40,
      overshootClamping: false,
    });

    opacity.value = withSpring(targetOpacity, {
      damping: 12,
      stiffness: 300,
      overshootClamping: true,
    });

    setTimeout(() => {
      if (direction === 'left') {
        setCards((prev) => prev.filter((_, i) => i !== currentIndex));
      } else {
        const newCard: CardData = {
          id: Date.now(),
          name: `New Person ${currentIndex + 1}`,
          age: Math.floor(Math.random() * (35 - 20) + 20),
          image: `https://images.unsplash.com/photo-${Math.floor(
            Math.random() * 10000000000
          )}?w=400&h=500&fit=crop`,
          bio: 'Just another interesting person!',
        };
        setCards((prev) => [newCard, ...prev]);
      }

      setCurrentIndex((prev) => prev + 1);
      translateX.value = 0;
      rotate.value = 0;
      scale.value = 1;
      opacity.value = 1;
    }, 300);
  };

  const currentCard = cards[currentIndex];

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [
        { translateX: translateX.value },
        { rotate: rotate.value * (Math.PI / 180) },
        { scale: scale.value },
      ],
      opacity: opacity.value,
    };
  });

  if (!currentCard) {
    return (
      <GestureHandlerRootView style={styles.container}>
        <View style={[styles.centerContent, styles.noCards]}>
          <Text style={styles.noCardsText}>No more cards!</Text>
          <TouchableOpacity
            style={styles.refreshButton}
            onPress={() => {
              setCards(initialCards);
              setCurrentIndex(0);
              translateX.value = 0;
              rotate.value = 0;
              scale.value = 1;
              opacity.value = 1;
            }}
          >
            <Text style={styles.refreshButtonText}>Refresh</Text>
          </TouchableOpacity>
        </View>
      </GestureHandlerRootView>
    );
  }

  return (
    <GestureHandlerRootView style={styles.container}>
      <Animated.View style={[styles.cardContainer, animatedStyle]}>
        <TouchableOpacity
          activeOpacity={1}
          onPress={() => handleSwipe('left')}
          onLongPress={() => handleSwipe('right')}
          style={styles.touchArea}
        >
          <View style={styles.imageContainer}>
            <Image source={{ uri: currentCard.image }} style={styles.cardImage} />
            <View style={styles.overlay}>
              <Text style={styles.name}>{currentCard.name}</Text>
              <Text style={styles.age}>{currentCard.age} years</Text>
            </View>
          </View>

          <View style={styles.bioContainer}>
            <Text style={styles.bio}>{currentCard.bio}</Text>
          </View>

          <View style={styles.actionButtons}>
            <TouchableOpacity
              style={[styles.actionButton, styles.noStyle]}
              onPress={() => handleSwipe('left')}
            >
              <Text style={styles.actionButtonText}>✕</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={[styles.actionButton, styles.likeStyle]}
              onPress={() => handleSwipe('right')}
            >
              <Text style={styles.actionButtonText}>♥</Text>
            </TouchableOpacity>
          </View>
        </TouchableOpacity>
      </Animated.View>
    </GestureHandlerRootView>
  );
};

