import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  ActivityIndicator,
  FlatList,
  TouchableOpacity,
} from 'react-native';

interface User {
  id: number;
  name: string;
  email: string;
}

interface Post {
  id: number;
  title: string;
  body: string;
}

const API_BASE_URL = 'https://jsonplaceholder.typicode.com';

export default function ParallelFetchComponent() {
  const [users, setUsers] = useState<User[]>([]);
  const [posts, setPosts] = useState<Post[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [usersResponse, postsResponse] = await Promise.all([
          fetch(`${API_BASE_URL}/users`),
          fetch(`${API_BASE_URL}/posts`),
        ]);

        if (!usersResponse.ok || !postsResponse.ok) {
          throw new Error('Failed to fetch data');
        }

        const usersData: User[] = await usersResponse.json();
        const postsData: Post[] = await postsResponse.json();

        setUsers(usersData);
        setPosts(postsData);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  const renderItem = ({ item }: { item: User }) => (
    <View style={styles.card}>
      <Text style={styles.title}>{item.name}</Text>
      <Text style={styles.subtitle}>{item.email}</Text>
    </View>
  );

  const renderPostItem = ({ item }: { item: Post }) => (
    <TouchableOpacity style={styles.card} onPress={() => console.log(item)}>
      <Text style={styles.title}>{item.title}</Text>
      <Text style={styles.body} numberOfLines={2}>
        {item.body}
      </Text>
    </TouchableOpacity>
  );

  if (loading) {
    return (
      <View style={styles.centerContainer}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading data...</Text>
      </View>
    );
  }

  if (error) {
    return (
      <View style={styles.centerContainer}>
        <Text style={styles.errorText}>{error}</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>Parallel API Fetch Demo</Text>
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Users ({users.length})</Text>
        {users.length > 0 ? (
          <FlatList
            data={users}
            renderItem={renderItem}
            keyExtractor={(item) => item.id.toString()}
            horizontal
            showsHorizontalScrollIndicator={false}
            contentContainerStyle={styles.listContent}
          />
        ) : (
          <Text style={styles.emptyText}>No users loaded</Text>
        )}
      </View>

      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Posts ({posts.length})</Text>
        {posts.length > 0 ? (
          <FlatList
            data={posts}
            renderItem={renderPostItem}
            keyExtractor={(item) => item.id.toString()}
            contentContainerStyle={styles.listContent}
            scrollEnabled={false}
          />
        ) : (
          <Text style={styles.emptyText}>No posts loaded</Text>
        )}
      </View>

      <View style={styles.footer}>
        <Text style={styles.footerText}>
          Both endpoints fetched in parallel using Promise.all()
        </Text>
      </View>
    </View>
  );
}

