import React from 'react';
import { FlatList, StyleSheet, View } from 'react-native';

interface ItemData {
  id: number;
  title: string;
}

const ITEM_HEIGHT = 60;
const WINDOW_SIZE = 10;

const MemoizedItem = React.memo(({ item }: { item: ItemData }) => (
  <View style={styles.item}>
    <Text style={styles.text}>{item.title}</Text>
  </View>
));

MemoizedItem.displayName = 'MemoizedItem';

export default function OptimizedFlatList() {
  const [data, setData] = React.useState<ItemData[]>([]);

  React.useEffect(() => {
    // Generate 10,000 items for testing
    const newData: ItemData[] = [];
    for (let i = 0; i < 10000; i++) {
      newData.push({
        id: i,
        title: `Item ${i + 1}`,
      });
    }
    setData(newData);
  }, []);

  const getItemLayout = (
    _: number,
    index: number
  ): { length: number; offset: number; index } => ({
    length: ITEM_HEIGHT,
    offset: ITEM_HEIGHT * index,
    index,
  });

  return (
    <View style={styles.container}>
      <FlatList
        data={data}
        renderItem={({ item }) => <MemoizedItem item={item} />}
        keyExtractor={(item) => item.id.toString()}
        getItemLayout={getItemLayout}
        windowSize={WINDOW_SIZE}
        initialNumToRender={10}
        maxToRenderPerBatch={5}
        removeClippedSubviews={true}
        scrollEnabled={true}
        contentContainerStyle={styles.listContent}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  listContent: {
    padding: 8,
  },
  item: {
    height: ITEM_HEIGHT,
    backgroundColor: 'white',
    borderRadius: 4,
    paddingHorizontal: 12,
    marginBottom: 4,
  },
  text: {
    fontSize: 16,
    color: '#333',
  },
});

import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { createStackNavigator, StackScreenProps } from '@react-navigation/stack';
import { NavigationContainer } from '@react-navigation/native';

// Define param list types for each screen
type HomeParams = {};
type ProfileParams = { userId: string; userName?: string };
type SettingsParams = { theme?: 'light' | 'dark' };
type AboutParams = { version?: string };

// Create typed stack navigator
const Stack = createStackNavigator<RootStackParamList>();

export type RootStackParamList = {
  Home: {};
  Profile: ProfileParams;
  Settings: SettingsParams;
  About: AboutParams;
};

// Define screen props types
type HomeScreenProps = StackScreenProps<RootStackParamList, 'Home'>;
type ProfileScreenProps = StackScreenProps<RootStackParamList, 'Profile'>;
type SettingsScreenProps = StackScreenProps<RootStackParamList, 'Settings'>;
type AboutScreenProps = StackScreenProps<RootStackParamList, 'About'>;

// Home Screen Component
const HomeScreen: React.FC<HomeScreenProps> = ({ navigation }) => {
  const handleNavigateToProfile = () => {
    navigation.navigate('Profile', { userId: '123', userName: 'John Doe' });
  };

  const handleNavigateToSettings = () => {
    navigation.navigate('Settings', { theme: 'dark' as const });
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Home Screen</Text>
      <TouchableOpacity style={styles.button} onPress={handleNavigateToProfile}>
        <Text style={styles.buttonText}>Go to Profile</Text>
      </TouchableOpacity>
      <TouchableOpacity style={styles.button} onPress={handleNavigateToSettings}>
        <Text style={styles.buttonText}>Go to Settings</Text>
      </TouchableOpacity>
    </View>
  );
};

// Profile Screen Component
const ProfileScreen: React.FC<ProfileScreenProps> = ({ route, navigation }) => {
  const { userId, userName } = route.params;

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Profile</Text>
      <Text>User ID: {userId}</Text>
      <Text>Name: {userName || 'Not provided'}</Text>
      <TouchableOpacity style={styles.button} onPress={() => navigation.goBack()}>
        <Text style={styles.buttonText}>Back</Text>
      </TouchableOpacity>
    </View>
  );
};

// Settings Screen Component
const SettingsScreen: React.FC<SettingsScreenProps> = ({ route, navigation }) => {
  const { theme } = route.params;

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Settings</Text>
      <Text>Current Theme: {theme || 'light'}</Text>
      <TouchableOpacity style={styles.button} onPress={() => navigation.goBack()}>
        <Text style={styles.buttonText}>Back</Text>
      </TouchableOpacity>
    </View>
  );
};

// About Screen Component
const AboutScreen: React.FC<AboutScreenProps> = ({ route, navigation }) => {
  const { version } = route.params;

  return (
    <View style={styles.container}>
      <Text style={styles.title}>About</Text>
      <Text>Version: {version || '1.0.0'}</Text>
      <TouchableOpacity style={styles.button} onPress={() => navigation.goBack()}>
        <Text style={styles.buttonText}>Back</Text>
      </TouchableOpacity>
    </View>
  );
};

// Main App Component
const App: React.FC = () => {
  return (
    <NavigationContainer>
      <Stack.Navigator initialRouteName="Home">
        <Stack.Screen 
          name="Home" 
          component={HomeScreen} 
          options={{ title: 'Home' }}
        />
        <Stack.Screen 
          name="Profile" 
          component={ProfileScreen} 
          options={{ title: 'Profile' }}
        />
        <Stack.Screen 
          name="Settings" 
          component={SettingsScreen} 
          options={{ title: 'Settings' }}
        />
        <Stack.Screen 
          name="About" 
          component={AboutScreen} 
          options={{ title: 'About' }}
        />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

